mapper.sql:
select  from subtasks

    and warehouse_id = #{wareHouseId}

        and id = #{ew.id}


        and task_id = #{ew.taskId}


        and subtask_def_id = #{ew.subtaskDefId}


        and name = #{ew.name}


        and priority = #{ew.priority}


        and status = #{ew.status}


        and compensation = #{ew.compensation}


        and allow_manual = #{ew.allowManual}


        and created_at = #{ew.createdAt}


        and updated_at = #{ew.updatedAt}


        and current_instruction_index = #{ew.currentInstructionIndex}


        and completed_at = #{ew.completedAt}


        and remark = #{ew.remark}


        and selected_device_id = #{ew.selectedDeviceId}


        and activity_instance_id = #{ew.activityInstanceId}


        and area = #{ew.area}


        and workflow_def_id = #{ew.workflowDefId}


        and is_start_next_process = #{ew.isStartNextProcess}


        and free_device_id = #{ew.freeDeviceId}


        and check_aisle = #{ew.checkAisle}

choose.when:
SELECT * FROM (
SELECT * FROM subtasks
WHERE warehouse_id = #{warehouseId} AND status = #{status}
ORDER BY priority DESC, created_at ASC
) WHERE ROWNUM <= #{limit}

SELECT * FROM subtasks
WHERE warehouse_id = #{warehouseId} AND status = #{status}
ORDER BY priority DESC, created_at ASC
LIMIT #{limit}

choose.otherwise:
SELECT TOP (#{limit}) * FROM subtasks
WHERE warehouse_id = #{warehouseId} AND status = #{status}
ORDER BY priority DESC, created_at ASC

choose.when:
select TOP 1

FROM subtasks
where task_id = #{taskId}
and warehouse_id = #{wareHouseId}
and status != 'completed'
order by id asc
